request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?task
  ?taskName
  (COUNT(DISTINCT ?msg) AS ?messageCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5ee15f85aeb74d8d9e31df0e41fea6fe" .

  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo .

  {
    ?mf bbo:has_sourceRef ?task .
  }
  UNION
  {
    ?mf bbo:has_targetRef ?task .
  }

  OPTIONAL {
    ?mf bboExt:messageRef ?msgRef .
    FILTER(STRLEN(STR(?msgRef))>0)
    BIND(?msgRef AS ?msg)
  }
}
GROUP BY ?task ?taskName
HAVING (COUNT(DISTINCT ?msg) > 1)
ORDER BY DESC(?messageCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?mf
  ?mfName
  ?mfMsgRef
  ?src
  ?srcName
  ?tgt
  ?tgtName
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5ee15f85aeb74d8d9e31df0e41fea6fe" .
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo .
  OPTIONAL { ?mf bbo:name ?mfName . }
  OPTIONAL { ?mf bboExt:messageRef ?mfMsgRef . }

  OPTIONAL { ?mf bbo:has_sourceRef ?src .
              ?src bbo:name ?srcName . }
  OPTIONAL { ?mf bbo:has_targetRef ?tgt .
              ?tgt bbo:name ?tgtName . }
}
LIMIT 25
